package stringjavatnp;

public class stringimmutabledemo {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		String name = "Java";
		name.concat("Programming");
		System.out.println(name);

		
		
		String text = "";
		
		for(int i = 1;i<=5;i++) {
			text=text +i ;
			
		}
		System.out.println(text);
	}

}
